create table users (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, email varchar(255) not null unique, password_hash varchar(255) not null, full_name varchar(255) not null, mobile varchar(50), email_verified boolean not null default false, account_locked boolean not null default false, otp_hash varchar(255), otp_expires_at timestamptz);
create table user_roles (user_id uuid not null references users(id) on delete cascade, role varchar(30) not null, primary key(user_id, role));
create table refresh_token (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, user_id uuid not null references users(id), token varchar(500) not null unique, expires_at timestamptz not null, revoked boolean not null default false);
create table properties (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, owner_id uuid not null references users(id), title varchar(255) not null, type varchar(30) not null, address_line1 varchar(255) not null, address_line2 varchar(255), city varchar(120) not null, state varchar(120) not null, postal_code varchar(20) not null, rent_amount numeric(12,2) not null, advance_amount numeric(12,2) not null, due_day int not null, occupied boolean not null default false);
create table property_image (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, property_id uuid not null references properties(id), url varchar(1000) not null, alt_text varchar(255));
create table tenant_profile (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, user_id uuid not null references users(id), property_id uuid not null references properties(id), emergency_contact varchar(255), kyc_document_url varchar(1000), move_in_date date);
create table rental_agreement (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, property_id uuid not null references properties(id), tenant_id uuid not null references tenant_profile(id), start_date date not null, end_date date not null, agreement_pdf_url varchar(1000));
create table payment (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, payer_id uuid not null references users(id), property_id uuid not null references properties(id), type varchar(30) not null, status varchar(30) not null, amount numeric(12,2) not null, late_fee numeric(12,2), due_date date not null, gateway_order_id varchar(255), gateway_payment_id varchar(255), receipt_url varchar(1000));
create table invoice (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, payment_id uuid not null references payment(id), invoice_number varchar(100) not null unique, issued_date date not null, due_date date not null, pdf_url varchar(1000));
create table notification (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, recipient_id uuid not null references users(id), title varchar(255) not null, message varchar(2000) not null, channel varchar(50) not null, read_flag boolean not null default false);
create table audit_log (id uuid primary key, created_at timestamptz not null, updated_at timestamptz not null, deleted boolean not null default false, actor_email varchar(255), action varchar(120), entity_name varchar(120), entity_id varchar(120), metadata varchar(4000));
create index idx_users_email on users(email);create index idx_property_owner on properties(owner_id);create index idx_property_city on properties(city);create index idx_payment_payer on payment(payer_id);create index idx_payment_property on payment(property_id);create index idx_notification_recipient on notification(recipient_id);
